import{_ as l,o as i,c as t,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Q-F06: 存貨與債務穩定度審計 - finance-financial-analyst 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8064_東捷/20260429/F06_存貨與債務穩定度_財務分析專家.md","filePath":"審計報告庫/財務審計/8064_東捷/20260429/F06_存貨與債務穩定度_財務分析專家.md"}'),n={name:"審計報告庫/財務審計/8064_東捷/20260429/F06_存貨與債務穩定度_財務分析專家.md"};function r(o,a,s,c,h,_){return i(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="q-f06-存貨與債務穩定度審計-finance-financial-analyst-審計報告" tabindex="-1">Q-F06: 存貨與債務穩定度審計 - finance-financial-analyst 審計報告 <a class="header-anchor" href="#q-f06-存貨與債務穩定度審計-finance-financial-analyst-審計報告" aria-label="Permalink to &quot;Q-F06: 存貨與債務穩定度審計 - finance-financial-analyst 審計報告&quot;">​</a></h1><blockquote><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p></blockquote><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨金額變動趨勢為何？流動性資產是否足以覆蓋短期與長期債務？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：存貨歷經兩年激進去庫存（總額縮水 55.6%），製成品去化成功且 WIP 大增顯示新訂單湧入。現金獨力覆蓋總債務 8.8 倍，流動性無虞。（74字）</li><li><strong>風險評級</strong>：A（良）</li><li><strong>數據時效</strong>：根據截至 2025 年度（114 年）最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>： <ul><li>存貨總額：2,457M (22&#39;) → 1,740M (23&#39;) → 1,367M (24&#39;) → 1,090M (25&#39;)，CAGR -24.2%</li><li>製成品佔存貨比：71.3% (24&#39;) → 42.2% (25&#39;)，絕對額減 52.8%</li><li>在製品(WIP)：302M (24&#39;) → 517M (25&#39;)，暴增 71.2%</li><li>流動/速動比：2.46 / 1.82 (25&#39;)，雙創四年新高</li><li>現金/總有息債務覆蓋率：8.8x（現金 2,419M vs 總債務 275M）</li></ul></li><li><strong>診斷見解</strong>：公司完成了一輪深度庫存清理 (2022→2025 存貨天數從 228 天縮至 139 天)，製成品大量出清而 WIP 反向飆升，代表營運從「被動去庫存」切換至「主動接單投產」階段。資產負債表極其保守，零流動性斷鏈疑慮。（142字）</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="【存貨組成分析】" tabindex="-1">【存貨組成分析】 <a class="header-anchor" href="#【存貨組成分析】" aria-label="Permalink to &quot;【存貨組成分析】&quot;">​</a></h3><ul><li><strong>核心重點</strong>：最近三季存貨：Q1 1,294M → Q2 1,325M → Q3 1,282M → Q4 1,090M (QoQ -15%)。製成品 Q4 急降至 460M，WIP 增至 517M。</li><li><strong>深度見解</strong>：製成品佔比從 71.3% (24&#39;) 驟降至 42.2% (25&#39;)，年報附註證實跌價迴轉 71M（前年提列損失 105M），證明存貨已實際銷售去化。WIP 暴增 71% 反映投產重啟，配合營收 YOY +10.2%。結構反轉判定為「去庫存尾聲，重啟投產」。（144字）</li></ul><h3 id="【償債壓力測試】" tabindex="-1">【償債壓力測試】 <a class="header-anchor" href="#【償債壓力測試】" aria-label="Permalink to &quot;【償債壓力測試】&quot;">​</a></h3><ul><li><strong>核心重點</strong>：速動資產 3,086M / 短債 144M = 21.4x。流動資產 4,176M 覆蓋流動負債 1,699M 達 2.46x。短借從 343M (22&#39;) 降至 126M (25&#39;)。</li><li><strong>深度見解</strong>：僅憑現金 2,419M 即可償還所有短借 126M + 一年內到期長債 17.5M 共 143.5M，尚餘 2,275M。速動比 21.4x 表示即使營收腰斬也無違約風險。2.46x 流動比與極低槓桿使合約限制觸發機率趨零。（128字）</li></ul><h3 id="【跌價損失預警】" tabindex="-1">【跌價損失預警】 <a class="header-anchor" href="#【跌價損失預警】" aria-label="Permalink to &quot;【跌價損失預警】&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2024 提列跌價損失 105M（佔存貨 7.7%）；2025 因去化順利迴轉利益 71M。存貨天數從 228 天 (22&#39;) 降至 139 天 (25&#39;)。</li><li><strong>深度見解</strong>：2024 巨額跌價是對面板景氣急凍的超額清洗。清洗後存貨結構改善：WIP 佔 47.4% &gt; 製成品 42.2%，多數仍處加工階段，無立即跌價風險。半導體封測設備需求若續強，WIP 可順利出貨。（103字）</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><p><strong>空頭風險一 — 面板景氣二次回落</strong>：2025 年面板價格反彈主要來自政策補貼（以舊換新）與庫存循環，非終端需求結構性好轉。Omdia 報告指出 2025Q2 LCD 電視面板出貨量已降至 2019 年以來最低。若補貼退場後消費動能無以為繼，東捷的面板設備收入將再次承壓，新備料的 WIP (517M) 恐轉為呆料。現行跌價準備是否足以吸收二次衰退至關重要。對策：嚴控 WIP 增量與客戶預付款對齊，避免盲目備料。</p></li><li><p><strong>空頭風險二 — 先進封裝資本支出兌現率</strong>：東捷佈局 FOPLP/TGV 先進封裝設備，但此技術路線仍在早期商業化階段，大規模量產時間表可能遞延。若客戶端（如半導體封測廠）延緩資本支出，WIP 將無法出貨兌現。現金儲備雖強 (2,419M)，但過於保守的資產配置亦可能拖累 ROE — 公司需在「財務安全」與「資本效率」間取得平衡，而非僅靠現金囤積防禦。</p></li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind (TaiwanStockBalanceSheet)</strong>: OK — 2024Q1 至 2025Q4 季度資產負債表數據完整，存貨/現金/短長借數據與年報一致。</li><li><strong>年報 (2025_Q4_8064_合併.pdf)</strong>: OK — 附註十一「存貨」提供組成明細（原物料 113M、在製品 517M、製成品 460M）及跌價損失迴轉利益 71M。</li><li><strong>年報比對核對碼</strong>: <ul><li>2025 存貨: 1,089,933 (千元) [Balance Sheet p.8]</li><li>2024 存貨: 1,366,716 (千元) [Balance Sheet p.8]</li><li>存貨跌價損失 2024: 105,361 (千元) [Note 11 p.33]</li><li>存貨迴轉利益 2025: (71,007) (千元) [Note 11 p.33]</li></ul></li></ul>',19)])])}const M=l(n,[["render",r]]);export{u as __pageData,M as default};
